#[derive(Debug, Clone)]
pub struct CoherenceSignature {
    /// Entropy H ∈ [0,1] — how much echelons disagreed. Exact rational.
    pub entropy: Q,
    /// Pairwise echelon agreement — 4×4 boolean matrix.
    /// 6 independent pairs → 2^6 = 64 distinct configurations.
    pub agreement_matrix: [[bool; 4]; 4],
    /// Pairwise orbit distances — 4×4 exact rational matrix.
    /// RCF distance between echelon proposals. Invariant under G-action.
    pub orbit_distances: [[Q; 4]; 4],
    /// Most common orbit class in K-window. Anchors to historical trajectory.
    pub modal_orbit: [u8; 32],
    /// Orbit class transitions in K-window. Basin boundary crossings.
    pub basin_crossings: u64,
    /// Average C(Δ) change per step. Negative = improving. Exact rational.
    pub mean_coherence_delta: Q,
    /// K-steps held (T_k=0, stasis). Echelon deadlock count.
    pub stasis_count: u64,
    /// Size of the observation window.
    pub k_window: u64,
}

/// Compute the coherence signature from MDC result and recent orbit history.
pub fn compute_coherence_signature(
    mdc: &MdcResult,
    recent_orbits: &[[u8; 32]],
    recent_coherence_deltas: &[Q],
    stasis_count: u64,
) -> CoherenceSignature {
    let hints = [
        &mdc.physics_hint,
        &mdc.legal_hint,
        &mdc.strategic_hint,
        &mdc.security_hint,
    ];

    // Agreement: do echelons i and j target the same orbit class? (4-byte prefix match)
    let mut agreement = [[false; 4]; 4];
    for i in 0..4 {
        for j in 0..4 {
            agreement[i][j] = hints[i].orbit_target[..4] == hints[j].orbit_target[..4];
        }
    }

    // Orbit distances: byte-level absolute difference, normalized to Q.
    let mut distances = [[Q::zero(), Q::zero(), Q::zero(), Q::zero()],
                         [Q::zero(), Q::zero(), Q::zero(), Q::zero()],
                         [Q::zero(), Q::zero(), Q::zero(), Q::zero()],
                         [Q::zero(), Q::zero(), Q::zero(), Q::zero()]];
    for i in 0..4 {
        for j in 0..4 {
            if i == j { continue; }
            let dist: u32 = hints[i].orbit_target.iter()
                .zip(hints[j].orbit_target.iter())
                .map(|(a, b)| (*a as i32 - *b as i32).unsigned_abs())
                .sum();
            distances[i][j] = Q::new(BigInt::from(dist as i64), BigInt::from(32 * 255i64));
        }
    }

    // Modal orbit from recent K-window
    let modal_orbit = if recent_orbits.is_empty() {
        mdc.combined_target
    } else {
        let mut counts = std::collections::HashMap::new();
        for rcf in recent_orbits {
            let mut prefix = [0u8; 4];
            prefix.copy_from_slice(&rcf[..4]);
            let entry = counts.entry(prefix).or_insert((0u32, *rcf));
            entry.0 += 1;
        }
        counts.values().max_by_key(|(c, _)| *c).map(|(_, rcf)| *rcf).unwrap_or(mdc.combined_target)
    };

    // Basin crossings
    let basin_crossings = if recent_orbits.len() < 2 {
        0
    } else {
        recent_orbits.windows(2)
            .filter(|w| w[0][..4] != w[1][..4])
            .count() as u64
    };

    // Mean coherence delta
    let mean_coherence_delta = if recent_coherence_deltas.is_empty() {
        Q::zero()
    } else {
        let sum: Q = recent_coherence_deltas.iter().cloned().sum();
        sum / Q::new(BigInt::from(recent_coherence_deltas.len() as i64), BigInt::from(1))
    };

    CoherenceSignature {
        entropy: mdc.entropy.clone(),
        agreement_matrix: agreement,
        orbit_distances: distances,
        modal_orbit,
        basin_crossings,
        mean_coherence_delta,
        stasis_count,
        k_window: recent_orbits.len() as u64,
    }
}

