/// IRS Mode 1: project algebraic state into semantic space.
/// The algebra is not compressed. It is read as semantic content.
/// When perception is available, it IS what ascending reads — the system's
/// derivation of meaning from its own coherence.
pub fn irs_ascending(
    agent_state: &AgentStateRecord,
    signature: &CoherenceSignature,
    last_c7_passed: bool,
    last_coherence_delta: &Q,
    last_source: &str,
) -> IrsAscending {
    let orbit_class = agent_state.rcf_identity.iter()
        .take(8)
        .map(|b| format!("{b:02x}"))
        .collect::<String>();

    let c_int = agent_state.coherence_q1616 >> 16;
    let c_frac = agent_state.coherence_q1616 & 0xFFFF;
    let coherence = format!("{}.{:04}", c_int, c_frac * 10000 / 65536);

    let coherence_trend = if agent_state.coherence_delta_q1616 < -100 {
        "decreasing".to_string()
    } else if agent_state.coherence_delta_q1616 > 100 {
        "increasing".to_string()
    } else {
        "stable".to_string()
    };

    let c7 = C7Summary {
        passed: last_c7_passed,
        coherence_delta: format!("{}/{}", last_coherence_delta.numer(), last_coherence_delta.denom()),
        source: last_source.to_string(),
    };

    let sovereignty = if agent_state.sovereignty_intact() {
        "intact".to_string()
    } else {
        let flags = agent_state.sovereignty_flags;
        let mut broken = Vec::new();
        if flags & 0b001 == 0 { broken.push("kernel"); }
        if flags & 0b010 == 0 { broken.push("c2r"); }
        if flags & 0b100 == 0 { broken.push("interop"); }
        format!("degraded: {} boundary compromised", broken.join(", "))
    };

    IrsAscending {
        k_index: agent_state.k_index,
        orbit_class,
        coherence,
        coherence_trend,
        signature: signature.clone(),
        c7,
        sovereignty,
        perception: None, // Set by caller when perception data is available
    }
}

/// Serialize IRS ascending result to JSON.
/// Rationals as strings "3/8" not floats 0.375.
/// The LLM reads exact algebraic structure.
pub fn irs_ascending_to_json(r: &IrsAscending) -> String {
    let sig = &r.signature;

    let agreement_json: String = (0..4).map(|i| {
        let row: String = (0..4).map(|j| {
            if sig.agreement_matrix[i][j] { "true" } else { "false" }
        }).collect::<Vec<_>>().join(",");
        format!("[{}]", row)
    }).collect::<Vec<_>>().join(",");

    let distances_json: String = (0..4).map(|i| {
        let row: String = (0..4).map(|j| {
            format!("\"{}\"", if sig.orbit_distances[i][j].is_zero() {
                "0".to_string()
            } else {
                format!("{}/{}", sig.orbit_distances[i][j].numer(), sig.orbit_distances[i][j].denom())
            })
        }).collect::<Vec<_>>().join(",");
        format!("[{}]", row)
    }).collect::<Vec<_>>().join(",");

    let modal_hex = sig.modal_orbit.iter().take(8).map(|b| format!("{b:02x}")).collect::<String>();
    let mean_cd = format!("{}/{}", sig.mean_coherence_delta.numer(), sig.mean_coherence_delta.denom());
    let entropy_str = format!("{}/{}", sig.entropy.numer(), sig.entropy.denom());

    let perception_json = match &r.perception {
        Some(p) => format!(
            r#","perception":{{"class":"{}","coherence":"{}","empirical_basis":{},"derived_output":[{}]}}"#,
            p.class, p.coherence, p.empirical_basis, p.derived_output,
        ),
        None => String::new(),
    };

    format!(
        r#"{{"k_index":{},"orbit_class":"0x{}","coherence":"{}","coherence_trend":"{}","signature":{{"entropy":"{}","agreement":[{}],"orbit_distances":[{}],"modal_orbit":"{}","basin_crossings":{},"mean_coherence_delta":"{}","stasis_count":{},"k_window":{}}},"c7":{{"passed":{},"coherence_delta":"{}","source":"{}"}},"sovereignty":"{}"{}}}"#,
        r.k_index, r.orbit_class, r.coherence, r.coherence_trend,
        entropy_str, agreement_json, distances_json, modal_hex,
        sig.basin_crossings, mean_cd, sig.stasis_count, sig.k_window,
        r.c7.passed, r.c7.coherence_delta, r.c7.source, r.sovereignty,
        perception_json,
    )
}

