/// A structured intent from the human/LLM layer.
/// This is what enters the C2R boundary from above.
#[derive(Debug, Clone)]
pub struct TranslationRequest {
    pub coherence_intent: CoherenceIntent,
    pub preferred_dimension: Option<(usize, usize)>,
    pub max_epsilon: Option<Q>,
    pub weight_override: Option<EchelonWeights>,
}

#[derive(Debug, Clone, Copy, PartialEq)]
pub enum CoherenceIntent {
    /// Minimize C(Δ) — follow gradient.
    Decrease,
    /// Hold position — identity operator, T_k=0.
    Hold,
    /// Explore new basins — basin hop mode.
    Explore,
    /// Conjugate per-object — the rule is object-local, derive within each cluster.
    /// Touch found objects, refraction found opaque boundaries.
    Conjugate,
    /// Relate objects — discover inter-object displacement/mapping.
    /// Objects exist and the rule lives BETWEEN them, not WITHIN.
    Relate,
    /// No preference — let the sampler decide.
    Auto,
}

/// Constraints derived from intent. These feed the sampler.
#[derive(Debug, Clone)]
pub struct OperatorConstraints {
    pub mode_hint: SamplerModeHint,
    pub direction_lock: Option<(usize, usize)>,
    pub max_epsilon: Option<Q>,
    pub weights: EchelonWeights,
    /// Algebraic superposition of all intents as a continuous velocity blend.
    /// When present, overrides mode_hint-based velocity selection.
    /// 0 = full exploration (BasinHop). 1 = full identity (Hold).
    /// Intermediate values = weighted superposition of all intents.
    /// None = fall back to mode_hint (single intent selection).
    pub intent_blend: Option<Q>,
}

#[derive(Debug, Clone, Copy, PartialEq)]
pub enum SamplerModeHint {
    Gradient,
    BasinHop,
    Compound,
    Identity,
    /// Per-object: derive within each cluster independently.
    ObjectLocal,
    /// Inter-object: discover relational structure between clusters.
    InterObject,
    Auto,
}

/// Create a PerceptionSummary from a Perception result (backward compatible).
/// Does not carry sensory compound — use `perception_to_summary_with_cognition()`
/// when the full Cognition is available.
pub fn perception_to_summary(p: &crate::perception::Perception) -> PerceptionSummary {
    let class = match &p.class {
        crate::perception::PerceptionClass::Recognition => "recognition".to_string(),
        crate::perception::PerceptionClass::Derivable { .. } => "derivable".to_string(),
        crate::perception::PerceptionClass::Transmutable { .. } => "transmutable".to_string(),
    };
    let coherence = format!("{}/{}", p.coherence.numer(), p.coherence.denom());
    let derived_output = p.derived_output.iter()
        .map(|v| v.to_string()).collect::<Vec<_>>().join(",");
    PerceptionSummary {
        class,
        coherence,
        empirical_basis: p.empirical_basis,
        derived_output,
        object_count: 0,
        sparse: false,
        senses_congruent: true,
        refraction_transparent: true,
        transmutation_signal: false,
    }
}

/// Create a PerceptionSummary from a full Cognition result.
/// This carries the sensory compound through the ascending path.
/// The IRS loop can now read: "3 objects, opaque refraction, transmutation needed."
pub fn perception_to_summary_with_cognition(cog: &crate::perception::Cognition) -> PerceptionSummary {
    let p = &cog.perception;
    let class = match &p.class {
        crate::perception::PerceptionClass::Recognition => "recognition".to_string(),
        crate::perception::PerceptionClass::Derivable { .. } => "derivable".to_string(),
        crate::perception::PerceptionClass::Transmutable { .. } => "transmutable".to_string(),
    };
    let coherence = format!("{}/{}", p.coherence.numer(), p.coherence.denom());
    let derived_output = p.derived_output.iter()
        .map(|v| v.to_string()).collect::<Vec<_>>().join(",");

    let refraction_transparent = cog.senses.refraction.iter().all(|r| r.transparent);

    PerceptionSummary {
        class,
        coherence,
        empirical_basis: p.empirical_basis,
        derived_output,
        object_count: cog.inquiry.object_count,
        sparse: cog.comprehension.sparsity < Q::new(BigInt::from(1), BigInt::from(4)),
        senses_congruent: cog.inquiry.congruence.vision_touch_congruence > Q::new(BigInt::from(1), BigInt::from(2))
            && cog.inquiry.congruence.touch_refraction_congruence > Q::new(BigInt::from(1), BigInt::from(2)),
        refraction_transparent,
        transmutation_signal: cog.inquiry.congruence.transmutation_magnitude > Q::zero(),
    }
}

/// Derive CoherenceIntent from PerceptionClass (backward compatible).
/// Use `semantic_operator()` when the sensory compound is available.
pub fn intent_from_perception(p: &crate::perception::Perception) -> CoherenceIntent {
    match &p.class {
        crate::perception::PerceptionClass::Recognition => CoherenceIntent::Decrease,
        crate::perception::PerceptionClass::Derivable { .. } => CoherenceIntent::Auto,
        crate::perception::PerceptionClass::Transmutable { .. } => CoherenceIntent::Explore,
    }
}

/// The semantic operator — comprehension gate for the IRS loop.
///
/// Reads the sensory compound and determines what the descending path needs.
/// "Adequately" is the conjugator: not the maximum possible intent,
/// but the minimum sufficient intent to resolve this observation.
///
/// The operator asks: "given what I sensed, what tools do I need to ACT
/// on this adequately?" The answer is an intent that carries the
/// specificity of the compound.
///
/// This is the linguistic glue between sensing and acting.
/// Without it, the ascending path says "derivable" and the descending
/// path says "auto" — the compound dies at the translation boundary.
pub fn semantic_operator(
    perception: &crate::perception::Perception,
    summary: &PerceptionSummary,
) -> CoherenceIntent {
    // Step 1: If already understood, refine
    if matches!(&perception.class, crate::perception::PerceptionClass::Recognition) {
        return CoherenceIntent::Decrease;
    }

    // Step 2: Comprehend the sentence — what does the sensory compound say?

    // Objects exist AND rule bends between them → the rule is inter-object
    if summary.object_count >= 2 && !summary.refraction_transparent {
        // The senses say: "objects exist, rule is NOT uniform across boundaries."
        // Adequate action: discover the relation between objects.
        return CoherenceIntent::Relate;
    }

    // Objects exist AND rule is uniform → conjugate per-object
    if summary.object_count >= 2 && summary.refraction_transparent {
        return CoherenceIntent::Conjugate;
    }

    // Transmutation signal fired → explore (the algebra must change)
    if summary.transmutation_signal {
        return CoherenceIntent::Explore;
    }

    // Sparse observation with incomplete coherence → the system needs targeted sensing
    if summary.sparse && perception.coherence < num_rational::Ratio::one() {
        return CoherenceIntent::Conjugate;
    }

    // Senses are congruent but derivation incomplete → auto (let algebra decide)
    if summary.senses_congruent {
        return CoherenceIntent::Auto;
    }

    // Fallback: senses incongruent, no objects → explore
    CoherenceIntent::Explore
}

/// IRS Mode 2: translate intent to operator constraints.
/// Deterministic — no neural network in this path.
/// The C2R boundary is a structured parser.
pub fn irs_descending(request: &TranslationRequest) -> OperatorConstraints {
    let mode_hint = match request.coherence_intent {
        CoherenceIntent::Decrease => SamplerModeHint::Gradient,
        CoherenceIntent::Hold => SamplerModeHint::Identity,
        CoherenceIntent::Explore => SamplerModeHint::BasinHop,
        CoherenceIntent::Conjugate => SamplerModeHint::ObjectLocal,
        CoherenceIntent::Relate => SamplerModeHint::InterObject,
        CoherenceIntent::Auto => SamplerModeHint::Auto,
    };
    OperatorConstraints {
        mode_hint,
        direction_lock: request.preferred_dimension,
        max_epsilon: request.max_epsilon.clone(),
        weights: request.weight_override.clone().unwrap_or_else(EchelonWeights::balanced),
        intent_blend: None,
    }
}

/// Descend from weighted intent superposition to constraints.
/// All intents contribute simultaneously — none are selected away.
/// The velocity blend is the weighted sum of intent-implied velocities.
pub fn irs_descending_superposed(
    intents: &[(CoherenceIntent, Q)],
    preferred_dimension: Option<(usize, usize)>,
    max_epsilon: Option<Q>,
    weight_override: Option<EchelonWeights>,
) -> OperatorConstraints {
    // Map each intent to a velocity: 0 = explore, 1/2 = gradient, 1 = hold
    let total_weight: Q = intents.iter()
        .map(|(_, w)| w.clone())
        .fold(Q::zero(), |acc, w| acc + w);

    let blended_velocity: Q = intents.iter()
        .map(|(intent, w)| {
            let v = match intent {
                CoherenceIntent::Explore => Q::zero(),
                CoherenceIntent::Decrease => Q::new(BigInt::from(1), BigInt::from(2)),
                CoherenceIntent::Conjugate => Q::new(BigInt::from(1), BigInt::from(2)),
                CoherenceIntent::Relate => Q::new(BigInt::from(1), BigInt::from(3)),
                CoherenceIntent::Hold => Q::one(),
                CoherenceIntent::Auto => Q::new(BigInt::from(1), BigInt::from(2)),
            };
            v * w
        })
        .fold(Q::zero(), |acc, v| acc + v);

    let velocity = if total_weight > Q::zero() {
        blended_velocity / total_weight
    } else {
        Q::new(BigInt::from(1), BigInt::from(2)) // Auto
    };

    // The dominant intent determines the mode_hint for backward compatibility
    let dominant = intents.iter()
        .max_by(|a, b| a.1.cmp(&b.1))
        .map(|(intent, _)| *intent)
        .unwrap_or(CoherenceIntent::Auto);

    let mode_hint = match dominant {
        CoherenceIntent::Decrease => SamplerModeHint::Gradient,
        CoherenceIntent::Hold => SamplerModeHint::Identity,
        CoherenceIntent::Explore => SamplerModeHint::BasinHop,
        CoherenceIntent::Conjugate => SamplerModeHint::ObjectLocal,
        CoherenceIntent::Relate => SamplerModeHint::InterObject,
        CoherenceIntent::Auto => SamplerModeHint::Auto,
    };

    OperatorConstraints {
        mode_hint,
        direction_lock: preferred_dimension,
        max_epsilon,
        weights: weight_override.unwrap_or_else(EchelonWeights::balanced),
        intent_blend: Some(velocity),
    }
}

