    #[test]
    fn test_irs_ascending_valid_json() {
        let agent_state = AgentStateRecord {
            rcf_identity: [0xAB; 32], entity_id: 42, verifying_key: [0; 32],
            k_index: 8877, chain_length: 200,
            t_k_q1616: 65536, coherence_q1616: 16384,
            coherence_delta_q1616: -1000, sluice_state: 1,
            trajectory_phase: 0, sovereignty_flags: 0b111,
            receipt_tip_hash: [0; 16], anchor_hash: [0; 16],
        };
        use crate::mdc::{MdcResult, EchelonHint};
        let mdc = MdcResult {
            physics_hint: EchelonHint { orbit_target: [0xAA; 32], confidence: qr(9, 10) },
            legal_hint: EchelonHint { orbit_target: [0xAA; 32], confidence: qr(8, 10) },
            strategic_hint: EchelonHint { orbit_target: [0xBB; 32], confidence: qr(7, 10) },
            security_hint: EchelonHint { orbit_target: [0xAA; 32], confidence: qr(6, 10) },
            combined_target: [0xAA; 32], entropy: qr(3, 10),
            stasis: false, winner: Echelon::Physics,
            transmutation_needed: false,
        };
        let sig = compute_coherence_signature(&mdc, &[], &[qr(-1, 100), qr(-2, 100)], 0);
        let result = irs_ascending(&agent_state, &sig, true, &qr(-47, 1000), "coordinator");
        let json = irs_ascending_to_json(&result);

        let parsed: serde_json::Value = serde_json::from_str(&json).expect("IRS must produce valid JSON");
        assert_eq!(parsed["k_index"], 8877);
        assert!(parsed["signature"]["agreement"].is_array());
        assert_eq!(parsed["signature"]["entropy"], "3/10");
        assert_eq!(parsed["sovereignty"], "intact");
    }

