    #[test]
    fn test_irs_loop_coherence() {
        // The loop: ascending → intent → descending → constraints
        // Verify the output of ascending can inform descending
        let agent_state = AgentStateRecord {
            rcf_identity: [0x42; 32], entity_id: 1, verifying_key: [0; 32],
            k_index: 100, chain_length: 50,
            t_k_q1616: 0, coherence_q1616: 65536, // C = 1.0
            coherence_delta_q1616: -500, // improving
            sluice_state: 1, trajectory_phase: 0, sovereignty_flags: 0b111,
            receipt_tip_hash: [0; 16], anchor_hash: [0; 16],
        };
        use crate::mdc::{MdcResult, EchelonHint};
        let mdc = MdcResult {
            physics_hint: EchelonHint { orbit_target: [0xAA; 32], confidence: qr(9, 10) },
            legal_hint: EchelonHint { orbit_target: [0xAA; 32], confidence: qr(8, 10) },
            strategic_hint: EchelonHint { orbit_target: [0xAA; 32], confidence: qr(7, 10) },
            security_hint: EchelonHint { orbit_target: [0xAA; 32], confidence: qr(6, 10) },
            combined_target: [0xAA; 32], entropy: qr(1, 10),
            stasis: false, winner: Echelon::Physics,
            transmutation_needed: false,
        };
        let sig = compute_coherence_signature(&mdc, &[], &[qr(-1, 10)], 0);

        // Mode 1: ascending — reads algebraic state
        let ascending = irs_ascending(&agent_state, &sig, true, &qr(-1, 10), "sampler");
        assert_eq!(ascending.coherence_trend, "decreasing"); // system is improving

        // Human reads: "coherence decreasing, all echelons agree, keep going"
        // Human forms intent: "decrease" (continue gradient descent)
        let intent = TranslationRequest {
            coherence_intent: CoherenceIntent::Decrease,
            preferred_dimension: None,
            max_epsilon: None,
            weight_override: None,
        };

        // Mode 2: descending — translates intent to constraints
        let constraints = irs_descending(&intent);
        assert_eq!(constraints.mode_hint, SamplerModeHint::Gradient);

        // The loop closes: constraints → sampler → C7 → new orbit → new ascending
        // This test verifies the data flows correctly through both modes
    }

    // ── Semantic operator tests ──

    fn make_summary(object_count: usize, sparse: bool, refr_transparent: bool, xmute: bool) -> PerceptionSummary {
        PerceptionSummary {
            class: "derivable".to_string(),
            coherence: "0/1".to_string(),
            empirical_basis: 3,
            derived_output: String::new(),
            object_count,
            sparse,
            senses_congruent: refr_transparent,
            refraction_transparent: refr_transparent,
            transmutation_signal: xmute,
        }
    }

    fn make_perception_derivable() -> crate::perception::Perception {
        crate::perception::Perception {
            derived_output: vec![],
            coherence: qr(0, 1),
            class: crate::perception::PerceptionClass::Derivable {
                residual: qr(1, 1),
            },
            rule: crate::thinking::FactoredRule::NoRule,
            empirical_basis: 3,
            resolution: None,
            composition_depth: 0,
            symmetry: None,
            generator_source: None,
        }
    }

    #[test]
    fn test_semantic_operator_objects_opaque_refraction() {
        // 3 objects, refraction NOT transparent → Relate (inter-object)
        let p = make_perception_derivable();
        let s = make_summary(3, false, false, true);
        let intent = semantic_operator(&p, &s);
        assert_eq!(intent, CoherenceIntent::Relate,
            "objects + opaque refraction should produce Relate intent");
    }

    #[test]
    fn test_semantic_operator_objects_transparent() {
        // 2 objects, refraction transparent → Conjugate (per-object)
        let p = make_perception_derivable();
        let s = make_summary(2, false, true, false);
        let intent = semantic_operator(&p, &s);
        assert_eq!(intent, CoherenceIntent::Conjugate,
            "objects + transparent refraction should produce Conjugate intent");
    }

    #[test]
    fn test_semantic_operator_transmutation() {
        // No objects, transmutation signal → Explore
        let p = make_perception_derivable();
        let s = make_summary(0, false, true, true);
        let intent = semantic_operator(&p, &s);
        assert_eq!(intent, CoherenceIntent::Explore,
            "transmutation signal without objects should produce Explore intent");
    }

    #[test]
    fn test_semantic_operator_congruent_no_objects() {
        // No objects, senses congruent, derivable → Auto
        let p = make_perception_derivable();
        let s = make_summary(0, false, true, false);
        let intent = semantic_operator(&p, &s);
        assert_eq!(intent, CoherenceIntent::Auto,
            "congruent senses without objects should produce Auto intent");
    }

    #[test]
    fn test_semantic_operator_recognition() {
        // Recognition → Decrease regardless of compound
        let p = crate::perception::Perception {
            derived_output: vec![],
            coherence: qr(1, 1),
            class: crate::perception::PerceptionClass::Recognition,
            rule: crate::thinking::FactoredRule::NoRule,
            empirical_basis: 3,
            resolution: None,
            composition_depth: 0,
            symmetry: None,
            generator_source: None,
        };
        let s = make_summary(5, false, false, true);
        let intent = semantic_operator(&p, &s);
        assert_eq!(intent, CoherenceIntent::Decrease,
            "recognition should always produce Decrease regardless of compound");
    }

