    #[test]
    fn test_perception_summary_with_cognition() {
        // Full pipeline: cognize → summary → semantic operator
        let pairs = vec![(
            vec![1, 1, 0, 2, 2, 1, 1, 0, 2, 2],
            vec![2, 2, 0, 12, 12, 2, 2, 0, 12, 12],
        )];
        let cog = crate::perception::cognize(&pairs, &[1, 1, 0, 2, 2, 1, 1, 0, 2, 2], None);
        let summary = perception_to_summary_with_cognition(&cog);
        // Should carry object count and refraction data
        assert!(summary.object_count >= 2,
            "summary should carry object count from cognition, got {}", summary.object_count);
    }
